/* Evidence: cmem-worked-cmem-indeterminate-undefined-behavior-3 */
/* Browser practice: PicoC 3.2.2 C89/C90 plus selected C99. */
/* Changed case 1902; native C23 claims require explicit transfer gates. */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>


struct initialized_record { unsigned initialized; int value; };

static int worked_cmem_indeterminate_undefined_behavior_3(const struct initialized_record *record, int fallback) {
  if (record == NULL || !record->initialized) return fallback;
  return record->value;
}

int main(void) {
  struct initialized_record record = { 0u, 0 };
  int before = worked_cmem_indeterminate_undefined_behavior_3(&record, -1);
  record.value = 35;
  record.initialized = 1u;
  int after = worked_cmem_indeterminate_undefined_behavior_3(&record, -1);
  int invariant = before == -1 && after == 35;
  printf("initialization value=%d invariant=%d\n", after, invariant);
  return invariant ? 0 : 1;
}

